public int maxAlternatingSum(int[] nums) {
    long odd = 0, even = 0;
    for (int num : nums) {
        long newOdd = Math.max(even + num, odd);
        even = Math.max(odd - num, even);
        odd = newOdd;
    }
    return (int)odd;
}
```

